import{_ as a,c as r,o as t,a1 as l}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"高级工作流 | Superpowers 教程","description":"掌握 Superpowers 高级工作流，包括子代理驱动开发、代码审查、Git 工作树隔离、并发代理调度等高级技巧。本章节帮助你提升开发效率，实现快速迭代和高质量交付。","frontmatter":{"title":"高级工作流 | Superpowers 教程","sidebarTitle":"高级工作流","subtitle":"高级工作流","description":"掌握 Superpowers 高级工作流，包括子代理驱动开发、代码审查、Git 工作树隔离、并发代理调度等高级技巧。本章节帮助你提升开发效率，实现快速迭代和高质量交付。","order":150},"headers":[],"relativePath":"zh/obra/superpowers/advanced/index.md","filePath":"zh/obra/superpowers/advanced/index.md"}'),o={name:"zh/obra/superpowers/advanced/index.md"};function i(n,e,s,d,h,p){return t(),r("div",null,[...e[0]||(e[0]=[l('<h1 id="高级工作流" tabindex="-1">高级工作流 <a class="header-anchor" href="#高级工作流" aria-label="Permalink to &quot;高级工作流&quot;">​</a></h1><p>本章节讲解 Superpowers 的高级工作流和技巧，帮助你实现更高效、更专业的开发流程。核心内容涵盖子代理驱动开发、代码审查流程、环境隔离、并发调度等高级技能，以及完整的开发工作流实战。</p><h2 id="子页面导航" tabindex="-1">子页面导航 <a class="header-anchor" href="#子页面导航" aria-label="Permalink to &quot;子页面导航&quot;">​</a></h2><h3 id="子代理驱动开发-多任务快速迭代" tabindex="-1"><a href="./../subagent-development/">子代理驱动开发</a>：多任务快速迭代 <a class="header-anchor" href="#子代理驱动开发-多任务快速迭代" aria-label="Permalink to &quot;[子代理驱动开发](../subagent-development/)：多任务快速迭代&quot;">​</a></h3><p>利用子代理实现多个独立任务的快速迭代开发，执行两阶段自动审查（规格合规性 + 代码质量），避免上下文污染，自动化 TDD 流程和代码审查检查点。</p><h3 id="代码审查工作流-建立审查习惯" tabindex="-1"><a href="./../code-review-workflow/">代码审查工作流</a>：建立审查习惯 <a class="header-anchor" href="#代码审查工作流-建立审查习惯" aria-label="Permalink to &quot;[代码审查工作流](../code-review-workflow/)：建立审查习惯&quot;">​</a></h3><p>建立早期、频繁的代码审查习惯，在每个开发阶段主动请求代码审查。学习如何正确处理审查反馈，区分反馈优先级，进行技术性验证，保持代码质量基线。</p><h3 id="git-工作树隔离-隔离开发环境" tabindex="-1"><a href="./../git-worktrees/">Git 工作树隔离</a>：隔离开发环境 <a class="header-anchor" href="#git-工作树隔离-隔离开发环境" aria-label="Permalink to &quot;[Git 工作树隔离](../git-worktrees/)：隔离开发环境&quot;">​</a></h3><p>使用 Git worktrees 创建隔离的开发环境，保持主分支清洁。学习目录选择优先级、安全验证流程、项目设置和测试基线验证，实现并发安全的开发流程。</p><h3 id="并发代理调度-3-倍速度修复-bug" tabindex="-1"><a href="./../parallel-agents/">并发代理调度</a>：3 倍速度修复 Bug <a class="header-anchor" href="#并发代理调度-3-倍速度修复-bug" aria-label="Permalink to &quot;[并发代理调度](../parallel-agents/)：3 倍速度修复 Bug&quot;">​</a></h3><p>当面对多个独立问题时，并发调度多个子代理实现 3 倍效率提升。学习独立域识别、聚焦任务创建、并发派发和审查集成，适用于多测试失败、多子系统问题等场景。</p><h3 id="分支完成工作流-优雅结束开发" tabindex="-1"><a href="./../branch-completion/">分支完成工作流</a>：优雅结束开发 <a class="header-anchor" href="#分支完成工作流-优雅结束开发" aria-label="Permalink to &quot;[分支完成工作流](../branch-completion/)：优雅结束开发&quot;">​</a></h3><p>系统化处理开发分支的收尾工作，包括测试验证、分支合并、PR 创建和 Git worktree 清理。学习如何优雅地完成开发，避免遗留问题。</p><h3 id="完整开发工作流实战-从设计到部署" tabindex="-1"><a href="./../complete-workflow/">完整开发工作流实战</a>：从设计到部署 <a class="header-anchor" href="#完整开发工作流实战-从设计到部署" aria-label="Permalink to &quot;[完整开发工作流实战](../complete-workflow/)：从设计到部署&quot;">​</a></h3><p>综合所有 Superpowers 技能，演示从需求分析到功能部署的七大步骤完整开发工作流。通过真实场景实战，学会如何在项目中应用 brainstorming、TDD、代码审查等核心技能。</p><h2 id="学习路径建议" tabindex="-1">学习路径建议 <a class="header-anchor" href="#学习路径建议" aria-label="Permalink to &quot;学习路径建议&quot;">​</a></h2><p>建议按照以下顺序学习本章节内容：</p><ol><li><p><strong>子代理驱动开发</strong>（必学）</p><ul><li>这是高级工作流的核心技能</li><li>后续多个课程依赖于此</li></ul></li><li><p><strong>代码审查工作流</strong>（推荐）</p><ul><li>建立良好的审查习惯</li><li>配合子代理驱动开发使用</li></ul></li><li><p><strong>Git 工作树隔离</strong>（强烈推荐）</p><ul><li>创建安全的开发环境</li><li>避免主分支污染</li></ul></li><li><p><strong>并发代理调度</strong>（可选）</p><ul><li>在特定场景下提升效率</li><li>需要熟悉子代理驱动开发</li></ul></li><li><p><strong>分支完成工作流</strong>（推荐）</p><ul><li>规范化开发收尾流程</li><li>配合其他高级技能使用</li></ul></li><li><p><strong>完整开发工作流实战</strong>（综合实战）</p><ul><li>将所有技能融会贯通</li><li>建议最后学习</li></ul></li></ol><div class="tip custom-block"><p class="custom-block-title">学习建议</p><ul><li><strong>循序渐进</strong>：建议按课程顺序学习，每个技能都依赖前面的知识</li><li><strong>实践为主</strong>：高级工作流需要大量实践，不要只看不练</li><li><strong>结合场景</strong>：根据你的实际项目需求，选择最需要的技能深入学习 ::</li></ul><h2 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h2><p>学习本章节需要你已经完成以下基础内容：</p><ul><li>✅ <strong>核心工作流</strong>（<a href="./../../core-workflows/">core-workflows</a>）： <ul><li><a href="./../../core-workflows/design-workflow/">设计工作流：Brainstorming</a></li><li><a href="./../../core-workflows/planning-workflow/">计划工作流：Writing Plans</a></li><li><a href="./../../core-workflows/tdd-workflow/">测试驱动开发：TDD 铁律</a></li><li><a href="./../../core-workflows/debugging-workflow/">调试工作流：Systematic Debugging</a></li><li><a href="./../../core-workflows/verification-workflow/">验证工作流：证据优先</a></li></ul></li></ul><div class="warning custom-block"><p class="custom-block-title">为什么需要前置条件？</p><p>高级工作流建立在核心工作流之上，如果缺少基础，高级技巧可能无法正确应用或导致问题。建议先完成核心工作流的学习。 ::</p><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><p>本章节的高级工作流适用于以下场景：</p><table tabindex="0"><thead><tr><th>场景</th><th>推荐课程</th></tr></thead><tbody><tr><td>需要快速完成多个独立任务</td><td><a href="./../subagent-development/">子代理驱动开发</a></td></tr><tr><td>团队协作，需要代码审查</td><td><a href="./../code-review-workflow/">代码审查工作流</a></td></tr><tr><td>需要同时进行多个开发任务</td><td><a href="./../git-worktrees/">Git 工作树隔离</a></td></tr><tr><td>遇到多个独立的 Bug 或问题</td><td><a href="./../parallel-agents/">并发代理调度</a></td></tr><tr><td>需要规范化的分支管理</td><td><a href="./../branch-completion/">分支完成工作流</a></td></tr><tr><td>想掌握完整开发流程</td><td><a href="./../complete-workflow/">完整开发工作流实战</a></td></tr></tbody></table><h2 id="下一步指引" tabindex="-1">下一步指引 <a class="header-anchor" href="#下一步指引" aria-label="Permalink to &quot;下一步指引&quot;">​</a></h2><p>完成本章节学习后，你可以：</p><ul><li>📚 <strong>编写自定义技能</strong>：学习 <a href="./../../extending/writing-skills/">编写自定义技能</a>，创建适合自己的 Superpowers 技能</li><li>🧪 <strong>测试你的技能</strong>：学习 <a href="./../../extending/testing-skills/">测试技能</a>，验证技能的正确性</li><li>🤝 <strong>贡献给社区</strong>：学习 <a href="./../../extending/contributing/">贡献指南</a>，将你的技能分享给社区</li></ul><div class="info custom-block"><p class="custom-block-title">进阶路径</p><p>Superpowers 的强大之处在于可扩展性。完成高级工作流学习后，建议探索 <a href="./../../extending/">extending</a> 章节，学会如何编写和贡献自己的技能。 ::</p></div></div></div>',19)])])}const g=a(o,[["render",i]]);export{u as __pageData,g as default};
